<?php
namespace app\Repositories;
class DashboardRepository extends BaseRepository{ public function statistics(string $date=''):array{ $date=$date?:date('Y-m-d'); $p=[$date]; $one=function($sql,$params=[]){ return (int)$this->fetch($sql,$params)['c']; }; return ['date'=>$date,'total_books'=>$one("SELECT COUNT(*) c FROM books"),'total_newspapers'=>$one("SELECT COUNT(*) c FROM newspapers"),'total_magazines'=>$one("SELECT COUNT(*) c FROM magazines"),'total_members'=>$one("SELECT COUNT(*) c FROM members"),'total_borrows'=>$one("SELECT COUNT(*) c FROM borrows WHERE borrow_date=?",$p),'borrowing_items'=>$one("SELECT COUNT(*) c FROM borrows WHERE status='borrowing' AND borrow_date<=?",$p),'returned_items'=>$one("SELECT COUNT(*) c FROM book_returns WHERE return_date=?",$p),'overdue_items'=>$one("SELECT COUNT(*) c FROM borrows WHERE status='borrowing' AND due_date<?",$p),'total_fines'=>(float)$this->fetch("SELECT COALESCE(SUM(fine_amount),0) c FROM book_returns WHERE return_date=?",$p)['c']]; } public function recentBorrows(string $date=''):array{ $date=$date?:date('Y-m-d'); return $this->fetchAll("SELECT br.*,m.full_name member_name,CASE br.item_type WHEN 'book' THEN b.title WHEN 'newspaper' THEN n.name WHEN 'magazine' THEN g.name END item_title FROM borrows br JOIN members m ON m.id=br.member_id LEFT JOIN books b ON br.item_type='book' AND b.id=br.item_id LEFT JOIN newspapers n ON br.item_type='newspaper' AND n.id=br.item_id LEFT JOIN magazines g ON br.item_type='magazine' AND g.id=br.item_id WHERE br.borrow_date=? ORDER BY br.id DESC LIMIT 8",[$date]); } public function lowStockItems():array{ return (new InventoryRepository())->lowStock(); }}
